prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?choreo ?start ?startName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5a8e825c3a9a4049b67ab53c2ba7abc8" ;
         tai:belongsTo ?org .
  ?model tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo ;
         bbo:name ?startName .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  FILTER NOT EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?start ?startName ?choreo WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5a8e825c3a9a4049b67ab53c2ba7abc8" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName (COUNT(DISTINCT ?startCandidate) AS ?numStartCandidates) WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5a8e825c3a9a4049b67ab53c2ba7abc8" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  # define start candidates as nodes in the choreography with no incoming SequenceFlow
  ?startCandidate ^bbo:has_sourceRef ?inEdge .
  FILTER EXISTS {
    ?inEdge a bbo:SequenceFlow .
    ?inEdge tai:belongsTo ?choreo .
  }
  FILTER NOT EXISTS {
    ?anyIn a bbo:SequenceFlow ;
           bbo:has_targetRef ?startCandidate ;
           tai:belongsTo ?choreo .
  }

  FILTER NOT EXISTS {
    ?startCandidate ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
GROUP BY ?task ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?choreo) AS ?choreoCount)
       (COUNT(DISTINCT ?task) AS ?taskCount)
       (COUNT(DISTINCT ?flow) AS ?sequenceFlowCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5a8e825c3a9a4049b67ab53c2ba7abc8" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
  OPTIONAL { ?flow a bbo:SequenceFlow ; tai:belongsTo ?choreo . }
}
GROUP BY ?model
